def resolve_update(listener: str, event: str, code: int, payload: bytes):
    update_cls = GENERATED_UPDATES_BY_NAME.get((listener, event))
    if update_cls is None:
        updates = GENERATED_UPDATES.get(code)
        if not updates:
            return None
        update_cls = updates[UPDATE_INDEX.get(code, 0)]
    return update_cls(payload)
